import{_ as s,C as a,o as e,c as n,H as p,Q as l}from"./chunks/framework.de6162a0.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"node/npm/workspace.md","filePath":"node/npm/workspace.md"}'),c={name:"node/npm/workspace.md"},t=l(`<h2 id="什么是工作区-workspaces" tabindex="-1">什么是工作区 workspaces？ <a class="header-anchor" href="#什么是工作区-workspaces" aria-label="Permalink to &quot;什么是工作区 workspaces？&quot;">​</a></h2><p>如果你想构建 <code>Monorepo 项目</code>的话，建议你使用 npm 提供的多包管理功能<code>工作区 workspaces</code>。</p><h2 id="什么是-monorepo-项目" tabindex="-1">什么是 Monorepo 项目? <a class="header-anchor" href="#什么是-monorepo-项目" aria-label="Permalink to &quot;什么是 Monorepo 项目?&quot;">​</a></h2><p>简单来说，就是将多个包放在一个项目中，这样就可以避免多次重复下载安装依赖，提升项目构建速度。</p><h2 id="如何创建-monorepo-项目" tabindex="-1">如何创建 Monorepo 项目? <a class="header-anchor" href="#如何创建-monorepo-项目" aria-label="Permalink to &quot;如何创建 Monorepo 项目?&quot;">​</a></h2><ol><li>新建一个 <code>my-workspace</code> 文件夹；</li><li>运行指令<code>npm init -y</code>，初始化 <code>package.json</code>文件；</li><li>在 <code>package.json</code>文件中，添加一个 &quot;workspaces&quot; 字段，并指定一个工作区目录的数组。例如：<div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#E1E4E8;">{</span></span>
<span class="line"><span style="color:#E1E4E8;">  </span><span style="color:#79B8FF;">&quot;name&quot;</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;my-workspace&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">  </span><span style="color:#79B8FF;">&quot;private&quot;</span><span style="color:#E1E4E8;">: </span><span style="color:#79B8FF;">true</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">  </span><span style="color:#79B8FF;">&quot;workspaces&quot;</span><span style="color:#E1E4E8;">: [</span><span style="color:#9ECBFF;">&quot;packages/*&quot;</span><span style="color:#E1E4E8;">]</span></span>
<span class="line"><span style="color:#E1E4E8;">}</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292E;">{</span></span>
<span class="line"><span style="color:#24292E;">  </span><span style="color:#005CC5;">&quot;name&quot;</span><span style="color:#24292E;">: </span><span style="color:#032F62;">&quot;my-workspace&quot;</span><span style="color:#24292E;">,</span></span>
<span class="line"><span style="color:#24292E;">  </span><span style="color:#005CC5;">&quot;private&quot;</span><span style="color:#24292E;">: </span><span style="color:#005CC5;">true</span><span style="color:#24292E;">,</span></span>
<span class="line"><span style="color:#24292E;">  </span><span style="color:#005CC5;">&quot;workspaces&quot;</span><span style="color:#24292E;">: [</span><span style="color:#032F62;">&quot;packages/*&quot;</span><span style="color:#24292E;">]</span></span>
<span class="line"><span style="color:#24292E;">}</span></span></code></pre></div></li></ol><p>好了，通过上述的操作，我们已经将 packages 目录定义为工作区了。</p><p>接下来，我们就可以在 packages 目录下创建多个包了，且每个包都是一个独立的项目。</p><h2 id="monorepo-项目中-如何安装依赖" tabindex="-1">Monorepo 项目中，如何安装依赖？ <a class="header-anchor" href="#monorepo-项目中-如何安装依赖" aria-label="Permalink to &quot;Monorepo 项目中，如何安装依赖？&quot;">​</a></h2><p>在工作区根目录的终端中，运行 <code>npm install jquery</code> 指令，这将给工作区中所有子包都安装<code>jquery</code>依赖项。</p><p>如果你只想给某个子包安装依赖的话，那么你可以使用 <code>npm install jquery --workspace=child-package-name</code> 指令。</p>`,11);function r(i,d,E,u,y,m){const o=a("PageHeader");return e(),n("div",null,[p(o,{content:"工作区 workspaces"}),t])}const q=s(c,[["render",r]]);export{h as __pageData,q as default};
